import{_ as p}from"./chunks/showcase_output_separation.Bu6w1WB3.js";import{C as c,o as g,c as u,E as o,j as e,a as d,a5 as s,a6 as n,a2 as i}from"./chunks/framework.CkaEw-3u.js";const h="/mug-typography-docs/image/inspector_output_separation_labeled.webp",b="/mug-typography-docs/image/placeholder-write-on-keyframes.svg",m="/mug-typography-docs/image/inspector_output_settings.webp",k=JSON.parse('{"title":"出力設定 (Output Settings)","description":"出力分離、Write On、表示順、Targets記法","frontmatter":{"title":"出力設定 (Output Settings)","description":"出力分離、Write On、表示順、Targets記法","pageClass":"reference-page","aside":false},"headers":[],"relativePath":"reference/reference-output-settings.md","filePath":"reference/reference-output-settings.md"}'),O={name:"reference/reference-output-settings.md"},v=Object.assign(O,{setup(S){const r={separation:{image:"/image/inspector_output_settings.webp",alt:"Output Separation",label:"Output Separation",sourceWidth:612,sourceHeight:895,top:0,bottom:450},writeOn:{image:"/image/inspector_output_settings.webp",alt:"Write On",label:"Write On · Manual Order",sourceWidth:612,sourceHeight:895,top:420,bottom:895}};return(_,t)=>{const l=c("ReferenceOverview"),a=c("InspectorCrop");return g(),u("div",null,[o(l,{eyebrow:"PARAMETER REFERENCE",title:"Output Settings",description:"文字やパーツを別系統へ分離し、表示範囲と出現順を制御します。コンポジットとWrite Onを扱う出力ページです。",items:[{icon:"⑂",title:"Separation",description:"最大3系統へ出力を分離",href:"#パラメーター"},{icon:"✎",title:"Write On",description:"文字・パーツを順番に表示",href:"#write-on出現フィルター"},{icon:"↕",title:"Manual Order",description:"表示順を明示的に指定",href:"#表示順を手動で決める"},{icon:"{}",title:"Targets",description:"文字・パーツの指定記法",href:"#targets対象指定の記述フォーマット"}]}),t[0]||(t[0]=e("p",null,[d("特定のパーツや文字だけを別の出力として分離・抽出したり、一部の要素だけを描画したりするための設定ページです。"),e("br"),d(" この機能を利用することで、同一テキストの複数インスタンスに対してそれぞれ個別のパーツだけを透明背景で出力させ、後段のノードで異なるカラー・エフェクトを個別に合成するような高度なコンポジットが可能になります。")],-1)),t[1]||(t[1]=e("h2",{id:"パラメーター",tabindex:"-1"},[d("パラメーター "),e("a",{class:"header-anchor",href:"#パラメーター","aria-label":'Permalink to "パラメーター"'},"​")],-1)),o(a,s(n(r.separation)),null,16),t[2]||(t[2]=i('<table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Enable Output Separation</strong></td><td>出力分離機能を有効にします。ON にすると、以下のパラメーターが表示されます。</td><td>OFF</td></tr><tr><td><strong>Output Mode</strong></td><td>分離対象をどのように描画するかを指定します。以下の3つから選択可能です。<br>・<strong>Default</strong>: Separation 1・Separation 2 の<strong>どちらにも</strong>含まれていないパーツをレンダリングします（バウンディングボックス背景も描画されます）。<br>・<strong>Separation 1 Only</strong>: Separation 1 Targets で指定したパーツ「のみ」をレンダリングします（バウンディングボックス背景は描画されません）。<br>・<strong>Separation 2 Only</strong>: Separation 2 Targets で指定したパーツ「のみ」をレンダリングします（バウンディングボックス背景は描画されません）。</td><td>Default</td></tr><tr><td><strong>Separation 1 Targets</strong></td><td>第1分離グループの対象とする文字・パーツを指定するテキスト入力欄です。記述方法は下記の「<a href="#targets対象指定の記述フォーマット">Targets（対象指定）の記述フォーマット</a>」を参照してください。<br><strong>空欄の場合、その分離グループには何も含まれません</strong>（＝そのグループは対象なしになります）。</td><td>(空)</td></tr><tr><td><strong>Separation 2 Targets</strong></td><td>第2分離グループの対象とする文字・パーツを指定するテキスト入力欄です。記述方法は Separation 1 Targets と同じです（空欄の場合は何も含まれません）。</td><td>(空)</td></tr></tbody></table><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>分離ターゲット（Separation 1 / 2 Targets）では、<strong>空欄＝そのグループには何も含まれない（対象なし）</strong> という扱いになります。後述するパス変形・手描き風エフェクトの Targets（空欄＝すべてが対象）とは空欄時の意味が逆になる点にご注意ください。</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>ワークフロー例</strong></p><ol><li>エフェクトノードをコピーして3つ作成します。</li><li>1つ目のノードで <code>Enable Output Separation</code> を ON、<code>Output Mode</code> を <code>Default</code> にし、<code>Separation 1 Targets</code> に <code>c1</code>、<code>Separation 2 Targets</code> に <code>c2</code> を指定します（1・2文字目以外が描画されます）。</li><li>2つ目のノードで <code>Enable Output Separation</code> を ON、<code>Output Mode</code> を <code>Separation 1 Only</code> にし、<code>Separation 1 Targets</code> に <code>c1</code> を指定します（1文字目だけが描画されます）。</li><li>3つ目のノードで <code>Enable Output Separation</code> を ON、<code>Output Mode</code> を <code>Separation 2 Only</code> にし、<code>Separation 2 Targets</code> に <code>c2</code> を指定します（2文字目だけが描画されます）。</li><li>各ノードに個別のエフェクトを適用してマージすることで、文字ごとに異なるエフェクトを持つアニメーション演出が実現できます。</li></ol></div><p><img src="'+h+'" alt="Output Separation ワークフロー例"><em>（出力分離の設定例。左: Output Mode = Separation 1 Only, 右: Output Mode = Default）</em></p><p><img src="'+p+'" alt="合成結果"><em>（各出力をマージした最終的な合成結果。左: Separation 1 のみにエフェクトを適用したもの, 右: 最終合成結果）</em></p><hr><p><a id="write-on-ja"></a></p><h2 id="✨-write-on-出現フィルター" tabindex="-1">✨ Write On（出現フィルター） <a class="header-anchor" href="#✨-write-on-出現フィルター" aria-label="Permalink to &quot;✨ Write On（出現フィルター）&quot;">​</a></h2><p><strong>Write On</strong> は、テキストの文字またはパーツを、先頭から末尾へと段階的に表示・非表示にするフィルター機能です。<br><code>Start</code> と <code>End</code> パラメーターをタイムラインでキーフレームすることで、文字が順番に現れていく「書き文字」風アニメーションを簡単に作成できます。</p>',9)),o(a,s(n(r.writeOn)),null,16),t[3]||(t[3]=i('<table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Unit</strong></td><td>フィルターの単位を選択します。<br>・<strong>Character</strong>: 文字（キャラクター）単位でフィルタリングします。<code>Start</code>〜<code>End</code> の範囲に含まれる文字のみ描画されます。<br>・<strong>Part</strong>: パーツ単位でフィルタリングします。<code>Stroke Order</code> との組み合わせで、書き順に近い順序でパーツを出現させられます。</td><td>Character</td></tr><tr><td><strong>Start</strong></td><td>表示範囲の開始位置を <code>0.0</code>（先頭）〜 <code>1.0</code>（末尾）の割合で指定します。アニメーション可能。</td><td><code>0.0</code></td></tr><tr><td><strong>End</strong></td><td>表示範囲の終了位置を <code>0.0</code>（先頭）〜 <code>1.0</code>（末尾）の割合で指定します。アニメーション可能。</td><td><code>1.0</code></td></tr><tr><td><strong>Stroke Order</strong></td><td>ON にすると、各文字のパーツを出現順序が自然に見えるよう並び替えます。<strong>Unit が Part のときに特に有効で</strong>、おおよそ書き順に近い順序でパーツが現れるライトオン効果を実現します。</td><td>OFF</td></tr><tr><td><strong>Manual Order</strong></td><td>ONにすると、Manual Order Listへ書いた文字・パーツを指定順に先頭へ移します。未指定の要素はその後に続きます。</td><td>OFF</td></tr><tr><td><strong>Manual Order List</strong></td><td>Write Onで表示する順序を<code>c1</code>、<code>p3</code>、<code>c1-c3</code>などで指定します。</td><td>(空)</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Write On アニメーションの作り方</strong></p><ol><li><code>Unit</code> を <code>Part</code> に設定し、<code>Stroke Order</code> を ON にします。</li><li>アニメーションの開始フレームで <code>End</code> を <code>0.0</code> にキーフレームします。</li><li>アニメーションの終了フレームで <code>End</code> を <code>1.0</code> にキーフレームします。</li><li>これだけで、文字を書いていくようなアニメーションが完成します。</li></ol></div><p><img src="'+b+'" alt="Write OnのEndを0から1へアニメーションする画面（準備中）"></p><h3 id="表示順を手動で決める" tabindex="-1">表示順を手動で決める <a class="header-anchor" href="#表示順を手動で決める" aria-label="Permalink to &quot;表示順を手動で決める&quot;">​</a></h3><p><strong>Manual Order</strong>をオンにすると、文字やパーツの表示順を明示できます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c3 c1 c2</span></span></code></pre></div><p>上の例では3文字目、1文字目、2文字目の順に表示し、それ以外の文字・パーツは後ろへ続きます。<code>c1-c3</code>や<code>p2-p5</code>の範囲指定も使用できます。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Manual Order ListはSeparation Targetsと似た記法ですが、<code>!</code>による除外指定には対応していません。Manual Orderでは「先に表示したい順序」だけを列挙してください。</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><code>Start</code> と <code>End</code> が両方デフォルト値（<code>Start = 0.0</code>、<code>End = 1.0</code>）の場合、Write On フィルターは無効（すべて表示）として処理されます。</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>Stroke Order の出現順序について</strong><br><code>Stroke Order</code> による並び替えは、本来の正しい筆順（書き順）を再現するものではありません。パーツの位置関係などから<strong>それらしい順序を内部アルゴリズムで推定して並べている</strong>もので、実際の書き順とは異なる場合があります。また、パーツへの分かれ方は使用するフォントのデータ構造によって決まるため（<a href="/mug-typography-docs/guide/core-concepts.html">基本的な考え方</a>を参照）、<strong>同じ文字でもフォントが変われば出現順が変わることがあります</strong>。意図した順序になるかは、実際のフォントでプレビュー確認してください。</p></div><p><a id="targets-format-ja"></a></p><h2 id="targets-対象指定-の記述フォーマット" tabindex="-1">Targets（対象指定）の記述フォーマット <a class="header-anchor" href="#targets-対象指定-の記述フォーマット" aria-label="Permalink to &quot;Targets（対象指定）の記述フォーマット&quot;">​</a></h2><p>Output Separation の <code>Separation 1 / 2 Targets</code>、およびパス変形エフェクト・手描き風エフェクトの <code>Targets</code> は、いずれも同じ記述フォーマットで対象の文字・パーツを指定します。</p><p>トークン（指定の単位）を <strong>カンマ(<code>,</code>) またはスペース</strong>で区切って複数並べます。各トークンは以下の表記が使用できます（<strong>大文字・小文字は区別されません</strong>。<code>c1</code> と <code>C1</code> は同じ）。</p><table tabindex="0"><thead><tr><th>表記</th><th>意味</th><th>例</th></tr></thead><tbody><tr><td><code>c&lt;n&gt;</code></td><td><strong>文字単位</strong>。<code>n</code> 文字目（1始まり）を構成する<strong>すべてのパーツ</strong>を指定します。</td><td><code>c1</code> = 1文字目のすべてのパーツ</td></tr><tr><td><code>p&lt;n&gt;</code></td><td><strong>パーツ単位</strong>。グローバルで <code>n</code> 番目（1始まり）のパーツを指定します。</td><td><code>p5</code> = 5番目のパーツ</td></tr><tr><td><code>&lt;n&gt;</code></td><td><strong>プレフィックスなし</strong>。<code>p&lt;n&gt;</code> と同じく、<code>n</code> 番目のパーツを指定します。</td><td><code>15</code> = 15番目のパーツ（<code>p15</code> と同じ）</td></tr><tr><td><code>&lt;a&gt;-&lt;b&gt;</code></td><td><strong>範囲指定</strong>。<code>a</code> から <code>b</code> まで（両端を含む）をまとめて指定します。詳細は下記。</td><td><code>c1-c3</code>, <code>p2-p5</code>, <code>2-5</code></td></tr><tr><td><code>!&lt;トークン&gt;</code></td><td><strong>否定（除外）指定</strong>。先頭に <code>!</code> を付けると、そのトークンが選ぶ対象を<strong>除外</strong>します。詳細は下記。</td><td><code>!c2</code>, <code>!p3</code>, <code>!2-5</code></td></tr></tbody></table><h3 id="範囲指定-の詳しい挙動" tabindex="-1">範囲指定（<code>-</code>）の詳しい挙動 <a class="header-anchor" href="#範囲指定-の詳しい挙動" aria-label="Permalink to &quot;範囲指定（`-`）の詳しい挙動&quot;">​</a></h3><ul><li>範囲の両端は<strong>同じ種類</strong>（文字どうし、またはパーツどうし）である必要があります。種類が混在した指定（例: <code>c1-p3</code>）は無効として無視されます。</li><li><strong>片方の端だけにプレフィックスを付ければ十分です。</strong> プレフィックスのない端は、<strong>もう一方の端の種類を引き継ぎます</strong>。 <ul><li><code>c1-3</code> は <code>c1-c3</code> と同じ（1〜3文字目）として扱われます。<code>c1-c3</code> とすべて書く必要はありません。</li><li><code>1-3</code> は <code>p1-p3</code> と同じ（1〜3番目のパーツ）として扱われます。</li><li>引き継ぎは逆順でも働きます。<code>c3-1</code> は <code>c3-c1</code> → 並べ替えて <code>c1-c3</code> になります。</li></ul></li><li>開始と終了が逆順（例: <code>c3-c1</code>）でも、自動的に昇順に並べ替えて解釈されます。</li></ul><h3 id="否定指定-の詳しい挙動" tabindex="-1">否定指定（<code>!</code>）の詳しい挙動 <a class="header-anchor" href="#否定指定-の詳しい挙動" aria-label="Permalink to &quot;否定指定（`!`）の詳しい挙動&quot;">​</a></h3><ul><li><code>!</code> を付けたトークンは、その対象を結果から取り除きます。範囲や文字単位にも使えます（例: <code>!c2</code>, <code>!p3-p5</code>）。</li><li><strong>トークンの順序は問いません。</strong> すべての通常指定と除外指定を集計したうえで、<strong>除外が優先</strong>されます（同じパーツが指定と除外の両方に該当した場合は対象から外れます）。</li><li>否定指定は、各エフェクトの「空欄時の挙動」と組み合わせて使うと便利です（下記参照）。</li></ul><h3 id="空欄時の挙動-重要・機能ごとに逆" tabindex="-1">空欄時の挙動（重要・機能ごとに逆） <a class="header-anchor" href="#空欄時の挙動-重要・機能ごとに逆" aria-label="Permalink to &quot;空欄時の挙動（重要・機能ごとに逆）&quot;">​</a></h3><p>何も入力しなかった場合の扱いは、機能によって<strong>逆</strong>になります。</p><table tabindex="0"><thead><tr><th>機能</th><th>空欄時の意味</th></tr></thead><tbody><tr><td><strong>パス変形エフェクト / 手描き風エフェクト</strong>（Targets）</td><td><strong>すべての文字・パーツが対象</strong>になります。</td></tr><tr><td><strong>Output Separation</strong>（Separation 1 / 2 Targets）</td><td><strong>何も含まれません</strong>（対象なし）。</td></tr></tbody></table><p>このため、パス変形・手描き風エフェクトで「特定のパーツ<strong>以外</strong>すべて」を対象にしたい場合は、否定指定だけを書くのが便利です。たとえば <code>!c1</code> と入力すると、1文字目を除く<strong>すべて</strong>が対象になります（空欄＝全部 から 1文字目だけ除外されるため）。</p><h3 id="記述例" tabindex="-1">記述例 <a class="header-anchor" href="#記述例" aria-label="Permalink to &quot;記述例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入力</th><th>解釈</th></tr></thead><tbody><tr><td><code>c1, p12, 15</code></td><td>1文字目のすべてのパーツ、12番目のパーツ、15番目のパーツ</td></tr><tr><td><code>c1-c3</code></td><td>1〜3文字目のすべてのパーツ</td></tr><tr><td><code>c1-3</code></td><td><code>c1-c3</code> と同じ（1〜3文字目）。終端のプレフィックスは省略可</td></tr><tr><td><code>p2-p5</code> / <code>2-5</code></td><td>2〜5番目のパーツ（どちらも同じ）</td></tr><tr><td><code>c1-5 !c3</code></td><td>1〜5文字目のうち、3文字目を除いたすべて</td></tr><tr><td><code>!p3</code>（変形エフェクト側）</td><td>3番目のパーツを除く、すべてのパーツ</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>0以下の値や、存在しない範囲外のインデックス、種類が混在した範囲などの<strong>無効な指定は黙って無視されます</strong>（エラーにはなりません）。</p></div><details class="inspector-full-details"><summary><span>参考資料</span>Inspector全体をページ内で表示</summary><div class="inspector-full-grid inspector-full-grid-single"><img src="'+m+'" alt="Output Settings全体"></div></details><hr><p><a id="page-animation"></a></p>',29))])}}});export{k as __pageData,v as default};
